const cwd="/home/chao/VScode_projects/cli-subagents";
const cmds=[
  "test -f graphify-out/graph.json && graphify query \"What are the current WPQ4 WPQ5 WPQ6 WPQ7 authority states, dependencies, and fork merge order?\" --budget 1800",
  "git rev-parse HEAD && git status --short && git log --oneline -15",
  "wc -l blueprints/wpq4-grok-detached-busy.md blueprints/wpq5-delivery-confirm-replay.md blueprints/wpq6-watchdog-idle-reason.md blueprints/wpq7-callback-barrier.md GOLDEN-TIPS.md HANDOFF.md",
  "find .. -maxdepth 2 -type d -name cli-agent-orchestrator -o -type d -name tmp-wpq5-build -o -type d -name tmp-wpq6-build"
];
const rs=await Promise.all(cmds.map(cmd=>tools.exec_command({cmd,workdir:cwd,yield_time_ms:30000,max_output_tokens:12000})));
rs.forEach((r,i)=>{text(`CMD${i+1}\n${r.output}`)});
